            sourceSnippet2: 'Passport, PF, Aadhaar update: 7 financial changes that hit India from July 1, 2026 — WION',
            source3: 'The Hindu',
            sourceUrl3: 'https://www.thehindu.com/news/national/financial-changes-from-july-1-passport-epfo-itr-filing/article71164517.ece',
            sourceSnippet3: 'EPFO, passport to ITR: Major changes from July 1 — The Hindu',
            source4: 'Economic Times',
            sourceUrl4: 'https://m.economictimes.com/wealth/invest/financial-changes-from-july-1-2026-check-6-key-updates-on-itr-deadlines-aadhaar-passport-fees-sbi-and-hdfc-bank-credit-cards/articleshow/132031489.cms',
